script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f.getItem('d42')._controlBehavior.add_onRender(on$Voucher$GridRender);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultField(f);
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;set$Voucher$DefaultField(f);}
function close$Voucher$(f) {
  &ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.getItem('d42')._controlBehavior.remove_onRender(on$Voucher$GridRender);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d42')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
    &CancelStatusExplore;
    &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d42')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt:t_tien2,t_thue,t_tt');
    if (!f._udfQuantityPrice) v.addGridFields(g, 'tien_nt2,thue_nt:tien2,thue');
      else v.addGridFields(g, 'gia_nt,tien_nt2,thue_nt:gia,tien2,thue');
    v.addTotalFields(g, [['t_tien_nt2', 'tien_nt2'],['t_tien2', 'tien2'],['t_thue_nt', 'thue_nt'],['t_thue', 'thue']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      var a = [['d42', 'tk_no']];
      focus$Voucher$Tab(f, a);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  var a = ['d42'];
  focus$Voucher$Tab(sender.parentForm, a);
  &PostTabFocus;
}
function focus$Voucher$Tab(f, a) {
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;
  &PostTabChange;
  Array.add(a, 'ma_nvbh');
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$DebitAccount(o) {o.parentForm.request('DebitAccount', 'DebitAccount', ['tk'], o);}
function onChange$Voucher$TaxCode(o) {o.parentForm.request('GetTaxRate', 'GetTaxRate', ['ma_thue', 'loai_ct'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem("d42")._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
  g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_thue_no', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, &ResetCustInfoFields;);
      f.setItemControlBehavior('ten_khthue', result[4].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[5].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[6].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[7].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_nvbh', result[8].Value, result[9].Value, &ResetCustInfoFields;);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
   case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      changeHeader$Voucher$Transaction(f);
      break;
    case 'DebitAccount':
      f.setItemControlBehavior('tk_thue_no', result[0].Value, '');
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    &EIResponseCompleteChecking;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultField(f) {
  if (f._action == 'Edit') {
    f._customerIdentity = f.getItemValue('ma_kh');
  }
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');}

function changeHeader$Voucher$Transaction(f) {
  var v = (f.getItem('loai_ct').value == '2'), g = f.getItem("d42")._controlBehavior, field, j = g._getColumnOrder($func.trim('tk_no'));
  var c1 = (f._language == 'v' ? 'Tk có' : 'Credit Account'), c2 = (f._language == 'v' ? 'Tk nợ' : 'Debit Account'), _header = (v ? c1 : c2);
  field = g._fields[j - 1];
  g._setHeaderItemText(j, _header);
  g._fields[j - 1].HeaderText = _header;
  g._fields[j - 1].Label = _header;
  g._allFields[j - 1].HeaderText = _header;
}
function on$Voucher$GridRender(sender, eventArgs) {changeHeader$Voucher$Transaction(sender.get_element().parentForm);}
/* </flatten> */

      &ListScript;
      &PostScript;

